import type { Placement } from '@floating-ui/react';
import type { HTMLAttributes, ReactNode, RefObject } from 'react';
import type { TestComponentProps } from '../../types/test-component';
/**
 * Пропсы контейнера Dropdown — позиционируемый floating-выпадающий блок.
 * Не хранит логику выбора (single/multi); все состояния управляются снаружи.
 */
export interface DropdownProps extends TestComponentProps {
    /** Ссылка на якорный элемент, относительно которого позиционируется dropdown */
    anchorRef: RefObject<HTMLElement>;
    /** Управляемое состояние видимости */
    open: boolean;
    /** Вызывается, когда dropdown запрашивает открытие */
    onOpen?: () => void;
    /** Вызывается, когда dropdown запрашивает закрытие */
    onClose?: () => void;
    /** Вызывается при клике вне dropdown */
    onOutsideClick?: (event: MouseEvent) => void;
    /** Позиция относительно якоря */
    placement?: Placement;
    /** Вертикальный отступ от якоря (px) */
    verticalOffset?: number;
    /** Горизонтальный отступ от якоря (px) */
    horizontalOffset?: number;
    /** Режим ширины: по ширине якоря или по контенту */
    widthMode?: 'widthParent' | 'widthContent';
    /** Отображать ли оверлей */
    shouldRenderOverlay?: boolean;
    /** CSS-класс оверлея */
    overlayClassName?: string;
    /** Блокировать ли скролл за оверлеем */
    overlayScroll?: boolean;
    /** Учитывать ли скролл при вычислении позиции */
    scrollable?: boolean;
    /** Минимальная высота dropdown */
    minHeight?: number;
    /** ID корневого элемента приложения для портала */
    applicationRootElementID?: string;
    /** ID элемента dropdown */
    dropdownElementID?: string;
    /** Дополнительный CSS-класс */
    className?: string;
    /** Содержимое dropdown (обычно DropdownList) */
    children?: ReactNode;
}
/**
 * Пропсы DropdownList — прокручиваемый контейнер списка.
 */
export interface DropdownListProps extends HTMLAttributes<HTMLDivElement>, TestComponentProps {
    /** Идёт загрузка данных */
    loading?: boolean;
    /** Контент, отображаемый во время загрузки */
    loadingContent?: ReactNode;
    /** Список пуст (нет элементов) */
    empty?: boolean;
    /** Контент, отображаемый когда список пуст */
    emptyContent?: ReactNode;
    /** Контент над списком (например, поле фильтрации) */
    headerContent?: ReactNode;
    /** Контент под списком (например, кнопки действий) */
    footerContent?: ReactNode;
    /** Максимальная высота прокручиваемой области (px) */
    maxHeight?: number;
    /** Элементы списка (DropdownItem, DropdownSectionHeader, DropdownDivider и т. д.) */
    children?: ReactNode;
}
/**
 * Пропсы DropdownItem — единичный элемент списка.
 * Состояния selected/focused/disabled — чисто визуальные, передаются снаружи.
 */
export interface DropdownItemProps extends Omit<HTMLAttributes<HTMLDivElement>, 'children'>, TestComponentProps {
    /** Основной текст */
    label?: ReactNode;
    /** Дополнительный текст под label */
    description?: ReactNode;
    /** Контент слева (иконка, аватар, чекбокс, флаг и т. д.) */
    startAdornment?: ReactNode;
    /** Контент справа (иконка, текст, бейдж и т. д.) */
    suffix?: ReactNode;
    /** Визуальное состояние «выбран» */
    selected?: boolean;
    /** Визуальное состояние «в фокусе» (клавиатурная навигация) */
    focused?: boolean;
    /** Заблокированный элемент */
    disabled?: boolean;
    /** Полностью кастомное содержимое (заменяет label/description/adornments) */
    children?: ReactNode;
}
/**
 * Пропсы DropdownSectionHeader — заголовок секции.
 */
export interface DropdownSectionHeaderProps extends HTMLAttributes<HTMLDivElement>, TestComponentProps {
    /** Текст заголовка секции */
    label: ReactNode;
    /** Включает верхний бордер секции (используется вместо отдельного Divider между секциями) */
    withTopBorder?: boolean;
}
/**
 * Пропсы DropdownDivider — визуальный разделитель.
 */
export interface DropdownDividerProps extends HTMLAttributes<HTMLDivElement>, TestComponentProps {
    /** Горизонтальный отступ (inset) */
    inset?: boolean;
}
